SELECT MAX(iteration) AS max_iteration
FROM simulation_parameters
WHERE parameter_set_name = 'Initial Parameters';

SELECT simulation_id
FROM simulations
WHERE created_by = 1 AND birth_rate > 0.1;

SELECT MAX(end_date) AS most_recent_end_date
FROM simulations
WHERE simulation_id != 0 AND description = 'Initial simulation run';

SELECT simulation_id
FROM simulations
WHERE created_by = (SELECT user_id FROM users ORDER BY created_date DESC LIMIT 1);
